VALUES
  ('aboriginal-b0f95c3f-moex-00061', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依司法院大法官解釋，有關道路交通管理處罰條例第37條第3項限制計程車駕駛人於執業期中犯特 定之罪者，3年內不得執業，且吊銷其持有之各級駕照之規定，下列敘述何者錯誤？', '["其法律要件，不符比例原則，侵害工作權", "其法律要件，不符比例原則，侵害人身自由", "有關吊銷駕駛執照部分，不符比例原則，侵害工作權", "有關吊銷駕駛執照部分，不符比例原則，侵害一般行為自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00062', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依司法院釋字第803號解釋，關於原住民文化受憲法保護，下列敘述何者正確？', '["屬於個別原住民受憲法第22條保障之基本權利", "原住民有請求國家保障其文化之給付性權利", "涉及人性尊嚴，國家若加以限制，應為國會保留事項", "國家若為保護環境生態，而限制原住民狩獵文化權，司法應採合理標準予以審查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00063', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依憲法及增修條文規定，關於行政院組織，下列敘述何者錯誤？', '["行政院雖設有行政院會議，但實質上採取首長制", "基於法律保留原則，包括行政院及所屬機關之組織法規，均僅得以國會立法形式為之", "憲法增修條文對總統及行政院院長之權力雖有修正，在憲法本文中仍規定行政院為國家行政機關", "憲法增修條文變更憲法本文規定，賦予總統直接任命行政院院長之權力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00064', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '在權力分立下，有關立法權之敘述，下列何者正確？', '["立法院為國家最高立法機關，由人民選舉之立法委員組成之", "基於監督與制衡，立法院對行政院所提之預算案，得為必要增加支出之提議", "基於憲法採取的是內閣制，立法委員得兼任官吏", "立法委員之報酬或待遇，得授權以命令之方式規定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00065', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '下列何者不屬於監察院彈劾之對象？', '["司法院院長", "軍人", "地方行政首長", "地方民意代表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00066', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '有關政黨違憲解散之敘述，下列何者錯誤？', '["被解散之政黨，必須其目的或行為危害中華民國存在或自由民主憲政秩序", "須由其他政黨提出聲請", "須經言詞辯論始得判決", "須經憲法法庭審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00067', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依憲法訴訟法規定，下列何者為國家最高機關聲請憲法法庭判決之要件？', '["行使職權，適用憲法，發生疑義", "經確定終局裁判", "經行政救濟程序所適用", "行使職權，就所適用之法規範，認有牴觸憲法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00068', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依司法院大法官解釋，地方制度法有關縣（市）議會正副議長選舉之規定，下列敘述何者錯誤？', '["有關縣（市）議會正副議長選舉以記名投票為之，違背憲法第129條所定各種選舉應以無記名投票 方法行之", "縣（市）議會正副議長之選舉，應有議員、代表總額過半數之出席，以得票達出席總數之過半數者 為當選", "縣（市）議會正副議長之選舉結果無人當選時，應立即舉行第二次投票，以得票較多者為當選；得 票相同者，以抽籤定之", "中央法律要求地方議會應以記名投票方式選舉議長、副議長，並不侵害地方自治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00069', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '下列關於原住民族語言能力認證辦法之規定的敘述，何者正確？', '["本辦法之主管機關為教育部，族語能力認證工作由原住民族委員會負責辦理", "族語能力認證分為初級、中級、中高級、高級、優級及特優級", "參加族語能力認證者，不受國籍、族別及年齡之限制，但須從初級開始，逐級通過認證", "族語能力認證方式，包含測驗與審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00070', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '下列關於原住民族教育法之敘述，何者正確？', '["依據該法第4條的定義，一般教育係指為增加全國學生對於原住民族歷史文化之認識與素養提升， 所實施之教育", "依據該法第5條的規定，為發展及厚植原住民族知識體系，中央原住民族主管機關應會商教育、科 技、文化等主管機關，建構原住民族知識體系中長程計畫。前項中長程計畫，至少每3年通盤檢討 1次，並公告之", "依據該法第7條的規定，中央教育主管機關與中央原住民族主管機關應共同召開原住民族教育政策 會，進行包含原住民族教育體系、建構原住民族知識體系中長程計畫等原住民族教育政策之規劃、 制訂與審議", "依據該法第8條的規定，直轄市及所轄區域內有原住民族地區或原住民重點學校之縣（市），地方 政府應召開直轄市、縣（市）原住民族教育審議會，進行地方原住民族教育事項之審議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL)
